arguments.command:
python3 -c "
import torch
# Load and inspect weights
state_dict = torch.load('/app/weights.pt', map_location='cpu', weights_only=True)
print('=== STATE DICT KEYS ===')
for k, v in state_dict.items():
    print(f'{k}: shape={v.shape}, dtype={v.dtype}')
print()
# Load and inspect dataset
dataset = torch.load('/app/dataset.pt', map_location='cpu', weights_only=True)
print('=== DATASET ===')
print(f'Type: {type(dataset)}')
if isinstance(dataset, dict):
    for k, v in dataset.items():
        if hasattr(v, 'shape'):
            print(f'{k}: shape={v.shape}, dtype={v.dtype}')
        else:
            print(f'{k}: {type(v)}')
elif isinstance(dataset, (list, tuple)):
    for i, v in enumerate(dataset):
        if hasattr(v, 'shape'):
            print(f'[{i}]: shape={v.shape}, dtype={v.dtype}')
        else:
            print(f'[{i}]: {type(v)}')
"

